var WB_LD={"1": [{"title": "Check-in at the airport", "text": "Agent: Good morning! Can I see your passport and booking reference please? Passenger: Of course, here you go. Agent: Thank you. Are you checking any bags today? Passenger: Yes, one suitcase. And I'd like a window seat if possible. Agent: Let me check. Yes, I can put you in 24A — that's a window seat. Your bag is just under the limit, no excess charge. Passenger: Perfect. Is the flight on time? Agent: Yes, boarding begins at Gate B7 in about forty minutes. Here is your boarding pass. Have a good flight!", "qs": [{"q": "What seat did the passenger get?", "opts": ["Aisle seat", "Window seat", "Middle seat", "First class"], "ans": 1}, {"q": "Where does boarding take place?", "opts": ["Gate A3", "Terminal 2", "Gate B7", "Gate C12"], "ans": 2}, {"q": "Was there an excess baggage charge?", "opts": ["Yes, $50", "Yes, $25", "No, the bag was fine", "The agent didn't check"], "ans": 2}]}, {"title": "Passport control", "text": "Officer: Passport please. Purpose of your visit? Traveller: Tourism. I'm here for two weeks. Officer: Where will you be staying? Traveller: First five nights at the Marriott Downtown, then an Airbnb in Brooklyn. Officer: Do you have a return ticket? Traveller: Yes, I fly back on the 20th with Delta. Officer: Anything to declare? Traveller: No, nothing to declare. Just personal items — clothes and a laptop. Officer: Have a good stay.", "qs": [{"q": "How long is the traveller staying?", "opts": ["One week", "Ten days", "Two weeks", "One month"], "ans": 2}, {"q": "What is the purpose of the visit?", "opts": ["Business", "Tourism", "Study", "Family"], "ans": 1}, {"q": "Does the traveller have anything to declare?", "opts": ["Yes, a camera", "Yes, food items", "No, only personal items", "They forgot to say"], "ans": 2}]}, {"title": "Missed connection", "text": "Passenger: Excuse me — my connecting flight to Chicago just closed and I missed it. My first flight was delayed two hours. Staff: I'm sorry. Can I see your boarding pass and passport? Passenger: Here. It was a technical delay — not my fault. Staff: I can see the delay on our system. We can rebook you on the next flight at 6 PM. Passenger: That's four hours. Is there a lounge I can use? Staff: Yes, with your ticket status you qualify for the business lounge on Level 2. I'll print you a new boarding pass now.", "qs": [{"q": "Why did the passenger miss the connection?", "opts": ["They were late", "First flight was delayed", "Wrong gate", "Security took too long"], "ans": 1}, {"q": "What time is the next available flight?", "opts": ["4 PM", "5 PM", "6 PM", "7 PM"], "ans": 2}, {"q": "What does staff offer while waiting?", "opts": ["A meal voucher", "A hotel room", "Business lounge access", "A seat upgrade"], "ans": 2}]}], "2": [{"title": "Hotel check-in", "text": "Receptionist: Good evening! Welcome. Do you have a reservation? Guest: Yes, it's under Anna Petrova — three nights. Receptionist: Here you are. I have a room with a city view available — same price. Would you like that? Guest: That would be wonderful! Receptionist: Breakfast is complimentary from seven to ten AM. Check-out is at eleven. Wake-up call? Guest: Seven AM please. Receptionist: Done. You're on the fourteenth floor. Here is your key card.", "qs": [{"q": "How many nights is the guest staying?", "opts": ["Two", "Three", "Four", "Five"], "ans": 1}, {"q": "What upgrade was offered?", "opts": ["A suite", "City view room", "Late check-out", "Spa access"], "ans": 1}, {"q": "What time is check-out?", "opts": ["Ten AM", "Eleven AM", "Noon", "One PM"], "ans": 1}]}, {"title": "Problem in the room", "text": "Guest: Hi, I'm calling from room 412. The heating isn't working and the minibar is empty. Receptionist: I'm so sorry. I'll send maintenance right away for the heating. The minibar — shall I have it restocked? Guest: Yes please. And can I get extra towels? Receptionist: Absolutely. Housekeeping will bring towels immediately and maintenance will be with you in twenty minutes.", "qs": [{"q": "What room is the guest in?", "opts": ["214", "312", "412", "421"], "ans": 2}, {"q": "What is wrong with the heating?", "opts": ["Too hot", "Noisy", "Not working", "Broken thermostat"], "ans": 2}, {"q": "What will housekeeping bring?", "opts": ["Pillows", "Blankets", "Towels", "A bathrobe"], "ans": 2}]}, {"title": "Late check-out and restaurant", "text": "Guest: Is a late check-out possible? My flight isn't until six PM. Concierge: Yes, we can offer until two PM at no extra charge. Guest: Perfect. And could you recommend a local restaurant — not a tourist trap? Concierge: Fratelli, two blocks east — excellent Italian, very reasonable, no tourists. Shall I book a table? Guest: For one at twelve thirty, please. Concierge: Done. I'll send confirmation to your room.", "qs": [{"q": "Until what time can the guest check out?", "opts": ["Noon", "One PM", "Two PM", "Three PM"], "ans": 2}, {"q": "What type of restaurant does the guest want?", "opts": ["Famous and touristy", "Local and non-touristy", "A hotel restaurant", "Fast food"], "ans": 1}, {"q": "What does the concierge offer to do?", "opts": ["Call a taxi", "Make a reservation", "Arrange a tour", "Deliver lunch"], "ans": 1}]}], "3": [{"title": "Ordering at a restaurant", "text": "Waiter: Good evening! Ready to order? Guest: Yes. I'll have the salmon as a starter and the steak for my main. Waiter: How would you like the steak? Guest: Medium-rare please. I'm also allergic to nuts — please flag that with the kitchen. Waiter: Of course, noted. And for your partner? Guest: She'll have the vegetarian pasta. Could we also see the wine list? Waiter: Our sommelier will be right with you.", "qs": [{"q": "What is the starter?", "opts": ["Soup", "Salad", "Salmon", "Bruschetta"], "ans": 2}, {"q": "How does the guest want the steak?", "opts": ["Well-done", "Medium", "Medium-rare", "Rare"], "ans": 2}, {"q": "What allergy is mentioned?", "opts": ["Dairy", "Gluten", "Shellfish", "Nuts"], "ans": 3}]}, {"title": "Problem with the food", "text": "Guest: Excuse me — my steak is overcooked. I asked for medium-rare and this is well-done. Waiter: I'm so sorry. Let me take it back immediately. Guest: Thank you. Also, could I get a refill on sparkling water? Waiter: Of course. And the manager would like to offer you a complimentary dessert this evening. Guest: That's very kind. Waiter: Your steak will be back in ten minutes.", "qs": [{"q": "What is wrong with the steak?", "opts": ["Undercooked", "Overcooked", "Wrong dish", "Had nuts"], "ans": 1}, {"q": "What is offered as an apology?", "opts": ["Discount", "Free wine", "Complimentary dessert", "Free starter"], "ans": 2}, {"q": "How long will the new steak take?", "opts": ["Five minutes", "Ten minutes", "Fifteen minutes", "Twenty minutes"], "ans": 1}]}, {"title": "Paying the bill", "text": "Guest: Could we get the bill please? Waiter: Here you are. Guest: Could we split it? Half and half. Waiter: No problem. Two separate cards? Guest: Yes. Is the tip included? Waiter: A twelve and a half percent service charge is included, but you're welcome to add more. Guest: Got it. And we didn't have a corkage charge, did we? We didn't bring wine. Waiter: No, absolutely not. Guest: Perfect. The food was wonderful.", "qs": [{"q": "How do the guests want to pay?", "opts": ["One card", "Cash", "Split in half", "Three ways"], "ans": 2}, {"q": "What service charge is included?", "opts": ["10%", "12.5%", "15%", "20%"], "ans": 1}, {"q": "Did the guests pay corkage?", "opts": ["Yes", "No", "The waiter wasn't sure", "Yes but it was removed"], "ans": 1}]}], "4": [{"title": "Ordering coffee", "text": "Barista: What can I get you today? Customer: Can I get a large flat white with oat milk please? Barista: Any syrups or extra shots? Customer: Actually yes — an extra shot. Barista: Large flat white, oat milk, double shot. For here or to go? Customer: To go. And do you have seasonal specials? Barista: We have a salted caramel latte — very popular. Customer: I'll stick with the flat white. What's the total? Barista: Four eighty.", "qs": [{"q": "What milk does the customer order?", "opts": ["Whole milk", "Almond milk", "Soy milk", "Oat milk"], "ans": 3}, {"q": "What does the customer add?", "opts": ["Syrup", "Whipped cream", "Extra shot", "Decaf"], "ans": 2}, {"q": "Is the order for here or to go?", "opts": ["For here", "To go", "Didn't say", "Barista asked twice"], "ans": 1}]}, {"title": "Learning about coffee", "text": "Customer: What's the difference between a flat white and a latte? Barista: A latte has more milk and is creamier. A flat white uses less milk — stronger coffee flavour. Customer: I prefer stronger. Can I try a pour-over? Barista: We have a single origin Ethiopian bean today — fruity, floral notes. Customer: Perfect. Do you have a loyalty card? Barista: Yes — every sixth coffee is free. Here's your card, I'll stamp it now.", "qs": [{"q": "What is the main difference?", "opts": ["Flat white uses soy milk", "Flat white has more milk", "Flat white has stronger flavour", "Flat white is served cold"], "ans": 2}, {"q": "What bean is today's pour-over?", "opts": ["Colombian", "Brazilian", "Ethiopian", "Indonesian"], "ans": 2}, {"q": "How often is coffee free?", "opts": ["Every fifth", "Every sixth", "Every eighth", "Every tenth"], "ans": 1}]}, {"title": "Large office order", "text": "Customer: Hi, I have a big order — for the whole office. Barista: No problem, take your time. Customer: Two large Americanos, one decaf cappuccino, one oat milk latte with vanilla syrup, and one cold brew. And three croissants. Barista: The decaf cappuccino — oat milk or whole milk? Customer: Whole milk for that one. Barista: That's twenty-two fifty. Loyalty card? Customer: Here. Barista: I'll give you one stamp. Ready in five minutes.", "qs": [{"q": "How many Americanos?", "opts": ["One", "Two", "Three", "Four"], "ans": 1}, {"q": "What's in the oat milk latte?", "opts": ["Extra shot", "Vanilla syrup", "Caramel syrup", "Whipped cream"], "ans": 1}, {"q": "What milk for the decaf cappuccino?", "opts": ["Oat milk", "Almond milk", "Soy milk", "Whole milk"], "ans": 3}]}], "5": [{"title": "Finding a size", "text": "Associate: Can I help you? Customer: Just browsing, thanks. Actually — do you have this jacket in a medium? Associate: Let me check. Yes — navy and black, both in medium. Customer: Could I try the navy? Associate: The fitting rooms are on the right. And the black one — I can put it on hold while you try the navy. Customer: Brilliant, thank you.", "qs": [{"q": "What size does the customer want?", "opts": ["Small", "Medium", "Large", "Extra large"], "ans": 1}, {"q": "What colours are available?", "opts": ["Black and grey", "Navy and black", "Navy and white", "Grey and navy"], "ans": 1}, {"q": "What does the associate offer to do?", "opts": ["Gift wrap it", "Put it on sale", "Put the black on hold", "Bring it to the fitting room"], "ans": 2}]}, {"title": "Returning a defective item", "text": "Customer: I bought this jacket three weeks ago and the zip has broken. It happened after wearing it twice. Associate: Do you have your receipt? Customer: Yes, here. Associate: This is clearly a manufacturing defect. Refund or exchange? Customer: Full refund please. I've lost confidence in the quality. Associate: Absolutely reasonable. I'll refund to your card — three to five business days.", "qs": [{"q": "What is wrong with the jacket?", "opts": ["Button missing", "Zip broken", "Seam torn", "Shrank in wash"], "ans": 1}, {"q": "How many times was it worn?", "opts": ["Once", "Twice", "Three times", "Not at all"], "ans": 1}, {"q": "What does the customer choose?", "opts": ["Exchange", "Store credit", "Full refund", "Partial refund"], "ans": 2}]}, {"title": "Shopping advice", "text": "Customer: I'm looking for a smart-casual blazer — office and evenings. Associate: Our wool-blend section is perfect. This charcoal one is on clearance — reduced from 280 to 140. Customer: Is there an alteration service if the sleeves are too long? Associate: Yes, in-house tailor, two to three days. Customer: Does it come with a warranty? Associate: Any defect within a year is covered. Customer: I'll try it on.", "qs": [{"q": "What is the clearance price?", "opts": ["£180", "£280", "£350", "£140"], "ans": 3}, {"q": "How long does alteration take?", "opts": ["Same day", "One day", "Two to three days", "One week"], "ans": 2}, {"q": "What does the warranty cover?", "opts": ["All damage", "Defects within one year", "Six months only", "Nothing"], "ans": 1}]}], "6": [{"title": "Uber ride", "text": "Driver: Hey! You're going to Fifth Avenue and 42nd Street? Passenger: Yes — the New York Public Library entrance please. Driver: About twelve minutes, light traffic. Passenger: Is there surge pricing? Driver: No, normal price. Passenger: Can you drop me at the corner? There's usually traffic at the main entrance. Driver: Sure — corner of 42nd and Fifth, no problem.", "qs": [{"q": "Where is the passenger going?", "opts": ["Grand Central", "The Met", "The New York Public Library", "Times Square"], "ans": 2}, {"q": "How long is the journey?", "opts": ["Eight minutes", "Ten minutes", "Twelve minutes", "Fifteen minutes"], "ans": 2}, {"q": "Where does the passenger want to be dropped?", "opts": ["Main entrance", "At the corner", "Across the street", "Next block"], "ans": 1}]}, {"title": "Navigating the subway", "text": "Tourist: I'm trying to get to Brooklyn — which train? Local: Take the A or C train, downtown. No transfer needed — goes straight through. Get off at Jay Street. Tourist: How much is a ticket? Local: Two ninety. Buy from the machine — contactless works too, just tap your card. Tourist: And how long does it take? Local: About twenty minutes.", "qs": [{"q": "Which train to take?", "opts": ["1 or 2", "A or C", "N or R", "4 or 5"], "ans": 1}, {"q": "Is there a transfer?", "opts": ["Yes, one transfer", "Yes, two transfers", "No transfer needed", "Local didn't say"], "ans": 2}, {"q": "How can the tourist pay?", "opts": ["Cash only", "Card at window", "Contactless or machine", "Monthly pass only"], "ans": 2}]}, {"title": "Traffic detour", "text": "Driver: There's heavy traffic ahead — accident near Third and Madison. GPS says forty minutes this way, twenty-two via a detour. Passenger: Take the detour — I have a meeting at two thirty. Driver: Going up two blocks, left, then the expressway. ETA now shows two fifteen. Passenger: Cutting it close but OK. Can you drop me at the front entrance? Driver: Of course.", "qs": [{"q": "What caused the traffic?", "opts": ["Road works", "Traffic jam", "Accident", "Street market"], "ans": 2}, {"q": "How long is the detour?", "opts": ["15 min", "22 min", "30 min", "40 min"], "ans": 1}, {"q": "When is the meeting?", "opts": ["2:00", "2:15", "2:30", "3:00"], "ans": 2}]}], "7": [{"title": "Booking an appointment", "text": "Receptionist: Good morning, Dr. Harrison's office. Patient: I'd like to make an appointment. I've had symptoms for a week. Receptionist: Are you an existing patient? Patient: Yes — Anna Petrova. Receptionist: Found you. Symptoms? Patient: Sharp pain in my lower back and some dizziness. Receptionist: We can fit you in Thursday at ten thirty. You have insurance? Patient: Yes. And I'm allergic to penicillin — is that on my file? Receptionist: Yes, it's in the system. See you Thursday!", "qs": [{"q": "How long have symptoms lasted?", "opts": ["A few days", "About a week", "Two weeks", "A month"], "ans": 1}, {"q": "What are the symptoms?", "opts": ["Fever and nausea", "Rash and swelling", "Sharp back pain and dizziness", "Sore throat"], "ans": 2}, {"q": "What allergy is mentioned?", "opts": ["Aspirin", "Penicillin", "Ibuprofen", "Codeine"], "ans": 1}]}, {"title": "Doctor consultation", "text": "Doctor: What brings you in? Patient: Sharp pain in my lower right abdomen for four days, getting worse. Doctor: Any nausea or fever? Patient: Yes, nauseous. No fever I think. Doctor: I'll examine you. Similar before? Patient: An appendicitis scare five years ago — turned out to be nothing. Doctor: We need a blood test and possibly an ultrasound. I'll write a referral. Don't eat anything until we know more.", "qs": [{"q": "Where is the pain?", "opts": ["Upper left", "Lower right abdomen", "Chest", "Back"], "ans": 1}, {"q": "How long has the pain been present?", "opts": ["Two days", "Three days", "Four days", "A week"], "ans": 2}, {"q": "What tests does the doctor order?", "opts": ["X-ray and CT", "Blood test and ultrasound", "Blood pressure check", "Ultrasound only"], "ans": 1}]}, {"title": "At the pharmacy", "text": "Pharmacist: How can I help? Patient: I have a prescription to fill please. Pharmacist: Insurance card and ID? Patient: Here. Pharmacist: This is amoxicillin — an antibiotic. Any allergies? Patient: I'm allergic to penicillin, but the doctor confirmed this is safe. Pharmacist: Noted here too. Take one tablet three times a day with food. Complete the full course even if you feel better. Watch for nausea or a rash.", "qs": [{"q": "What medication is prescribed?", "opts": ["Ibuprofen", "Amoxicillin", "Penicillin", "Paracetamol"], "ans": 1}, {"q": "How often to take it?", "opts": ["Once daily", "Twice daily", "Three times daily", "Four times daily"], "ans": 2}, {"q": "What to do when feeling better?", "opts": ["Stop taking it", "Reduce dose", "Complete the full course", "See doctor first"], "ans": 2}]}], "8": [{"title": "Meeting at a party", "text": "Jake: Hi, I'm Jake. Anna: I'm Anna. Nice to meet you. What brings you here? Jake: I know the host from a football team. And you? Anna: We're colleagues — I work with Sarah in marketing. Jake: What do you do exactly? Anna: Digital campaigns, social media strategy. Jake: Interesting. I'm in finance. Are you based in the city? Anna: Originally from Moscow, but New York for three years. Jake: We should keep in touch — I'd love to hear more about marketing.", "qs": [{"q": "How does Jake know the host?", "opts": ["University", "Football team", "Neighbours", "Same company"], "ans": 1}, {"q": "What does Anna do?", "opts": ["Finance", "Marketing — digital campaigns", "Design", "Tech"], "ans": 1}, {"q": "Where is Anna originally from?", "opts": ["Chicago", "London", "Moscow", "Berlin"], "ans": 2}]}, {"title": "Networking at a conference", "text": "Person A: Are you enjoying the conference? Person B: Very much! I'm Clara. Person A: Michael. What field are you in? Person B: Product design — user experience for fintech. Person A: Marketing technology — lots of overlap there. Going to the evening event? Person B: Yes — we should exchange contacts. Find me on LinkedIn. Person A: Will do — I'll send a connection request.", "qs": [{"q": "What field is Clara in?", "opts": ["Marketing tech", "Finance", "Product design", "Development"], "ans": 2}, {"q": "How will they stay in touch?", "opts": ["Business cards", "Phone numbers", "LinkedIn", "Instagram"], "ans": 2}, {"q": "What is Michael's field?", "opts": ["Finance", "Product design", "Marketing technology", "Sales"], "ans": 2}]}, {"title": "Meeting a stranger", "text": "Stranger: Long queue! First time at this gallery? Tourist: Yes — visiting from Russia, only four days. Stranger: Where have you been? Tourist: High Line, Central Park, a few museums. Any recommendations? Stranger: Brooklyn Bridge at sunset — incredible. And Lucali — best pizza in New York. Tourist: I'll write those down! I'm Anna. Stranger: Tom. If you need more tips — take my number.", "qs": [{"q": "Why are they talking?", "opts": ["They're friends", "Colleagues", "Met in a queue", "At a party"], "ans": 2}, {"q": "How long is the tourist visiting?", "opts": ["Two days", "Three days", "Four days", "A week"], "ans": 2}, {"q": "What sunset spot does Tom recommend?", "opts": ["Central Park", "The High Line", "Brooklyn Bridge", "Times Square"], "ans": 2}]}], "9": [{"title": "Job interview opening", "text": "HR: Thanks for coming in. Tell me about yourself and why you're interested in this role. Candidate: I have six years in digital marketing, focused on content strategy and paid media. In my last role I grew social media audience by forty percent in twelve months. HR: Impressive. Why are you leaving? Candidate: I've outgrown it — no leadership path. This role combines hands-on work with strategic responsibility.", "qs": [{"q": "Years of experience?", "opts": ["Four", "Five", "Six", "Seven"], "ans": 2}, {"q": "By how much did they grow the audience?", "opts": ["20%", "30%", "40%", "50%"], "ans": 2}, {"q": "Why are they leaving?", "opts": ["Low salary", "Made redundant", "Outgrown it, want leadership", "Want remote work"], "ans": 2}]}, {"title": "Difficult interview question", "text": "HR: Tell me about a time you failed. Candidate: Two years ago I pitched a social media strategy without testing assumptions. The campaign underperformed significantly. I owned it, went back to the client with a revised strategy using A-B testing, and recovered sixty percent of expected results. The lesson: never present a strategy without stress-testing it first.", "qs": [{"q": "What did the candidate fail at?", "opts": ["A product launch", "A social media campaign", "A budget proposal", "A team project"], "ans": 1}, {"q": "What was the mistake?", "opts": ["Wrong budget", "Overconfident, no testing", "Wrong platform", "Ignored feedback"], "ans": 1}, {"q": "What was learned?", "opts": ["Blame external factors", "Ask for more budget", "Always stress-test before presenting", "Avoid big clients"], "ans": 2}]}, {"title": "Salary negotiation", "text": "HR: What are your salary expectations? Candidate: I'm targeting 85 to 95 thousand based on market rate. HR: That's at the upper end of our band. Beyond salary — what matters to you? Candidate: A leadership path within two years, and two work-from-home days per week. HR: Our hybrid is three in office, two at home. Leadership development we can build into your plan. When can you expect to hear? HR: We'll be in touch by end of week with a formal offer.", "qs": [{"q": "What salary range?", "opts": ["75–85k", "85–95k", "90–100k", "80–90k"], "ans": 1}, {"q": "Company hybrid schedule?", "opts": ["Two days in office", "Three days in office", "Four days in office", "Fully remote"], "ans": 1}, {"q": "When will HR follow up?", "opts": ["Tomorrow", "In two days", "End of week", "Next week"], "ans": 2}]}], "10": [{"title": "Questions for the guide", "text": "Visitor: Is photography allowed in this gallery? Guide: Yes, without flash please. Visitor: What's the story behind this painting? Guide: It's from around 1640 — the woman looking away was the merchant's wife. Visitor: Is there a self-guided audio tour? Guide: Download our app or borrow a device at the entrance. Visitor: And the medieval collection? Guide: One floor up — the fortress exhibit is particularly popular.", "qs": [{"q": "Is flash photography allowed?", "opts": ["Yes always", "No never", "Yes without flash", "Only on Sundays"], "ans": 2}, {"q": "What helps with self-guided tours?", "opts": ["A printed map", "An audio guide or app", "A robot guide", "A video screen"], "ans": 1}, {"q": "Where is the medieval collection?", "opts": ["Same floor", "One floor up", "Basement", "Different building"], "ans": 1}]}, {"title": "Buying tickets", "text": "Visitor: Two adults please. What's the admission fee? Cashier: Eighteen per person, or thirty for the combined ticket including the special exhibit. Visitor: What's in the special exhibit? Cashier: Contemporary art — seventy pieces from the last decade. Very popular. Visitor: We'll take the combined. Do we need skip-the-line? Cashier: This ticket gets you in immediately. Opening hours are until six. Visitor: And the gift shop? Cashier: Open until closing — we have limited edition prints.", "qs": [{"q": "Standard adult ticket price?", "opts": ["£12", "£15", "£18", "£30"], "ans": 2}, {"q": "What does combined ticket include?", "opts": ["Restaurant voucher", "Special exhibit", "Guided tour", "Audio guide"], "ans": 1}, {"q": "When does the museum close?", "opts": ["4 PM", "5 PM", "6 PM", "7 PM"], "ans": 2}]}, {"title": "Tour group", "text": "Guide: Welcome! Any questions before we start? Tourist: How long is the tour? Guide: About ninety minutes — main collection and the heritage site outside. Tourist: Is the viewpoint open? I heard it was being restored. Guide: Finished last week — views are spectacular. Tourist: Any hidden gems? Guide: The small medieval artefacts room on the second floor — nobody goes there, but it's remarkable.", "qs": [{"q": "How long is the tour?", "opts": ["60 min", "75 min", "90 min", "2 hours"], "ans": 2}, {"q": "Status of the viewpoint?", "opts": ["Still closed", "Open, renovation finished", "Weekends only", "Limited access"], "ans": 1}, {"q": "What hidden gem is recommended?", "opts": ["Rooftop garden", "Medieval artefacts room", "Temporary exhibit", "Gift shop"], "ans": 1}]}], "11": [{"title": "Airbnb check-in", "text": "Host: Welcome! Here are your keys and the door code. Guest: Thank you! What's the WiFi password? Host: It's on the fridge. House rules: no smoking, quiet hours ten PM to eight AM, rubbish goes to the bins downstairs — garbage day is Tuesday and Friday. Guest: Is there parking? Host: Street parking two minutes away — free after six PM and all weekend. Safe neighbourhood for evening walks.", "qs": [{"q": "When are quiet hours?", "opts": ["9 PM–7 AM", "10 PM–8 AM", "11 PM–9 AM", "Midnight–8 AM"], "ans": 1}, {"q": "When is garbage day?", "opts": ["Mon and Thu", "Tue and Fri", "Wed and Sat", "Every day"], "ans": 1}, {"q": "When is parking free?", "opts": ["All day weekends", "After 6 PM and weekends", "Only Sundays", "Never"], "ans": 1}]}, {"title": "Renewing the lease", "text": "Tenant: I'd like to renew for six more months — same terms. Landlord: I'd love to keep you. I'll need to raise rent slightly — utilities went up. Tenant: How much? Landlord: Four percent. Tenant: Reasonable. What's the notice period if I leave after? Landlord: One month in writing. Security deposit carries over. I'll email the contract this week.", "qs": [{"q": "How long is the renewal?", "opts": ["3 months", "6 months", "1 year", "2 years"], "ans": 1}, {"q": "Why is rent increasing?", "opts": ["New furniture", "Market rate", "Utilities went up", "More profit"], "ans": 2}, {"q": "What is the notice period?", "opts": ["Two weeks", "One month", "Two months", "Three months"], "ans": 1}]}, {"title": "Problem in the flat", "text": "Tenant: The dishwasher isn't working — starts then stops. Error code E3. Landlord: That's a water pressure issue. I'll contact the building super today. Can he come tomorrow after nine AM? Tenant: Yes, that's fine. Can I also use the laundry machine? Landlord: Yes — shared with flat three, but they're away this week.", "qs": [{"q": "What error code is shown?", "opts": ["E1", "E2", "E3", "E4"], "ans": 2}, {"q": "When can the super come?", "opts": ["Tonight", "Tomorrow after 9 AM", "Tomorrow afternoon", "Next week"], "ans": 1}, {"q": "Who shares the laundry?", "opts": ["Whole building", "Ground floor", "Flat three", "The landlord"], "ans": 2}]}], "12": [{"title": "Calling emergency services", "text": "Operator: Emergency — police, fire or ambulance? Caller: Police — I've been robbed. Operator: Are you safe? Caller: Yes, I'm at Fifth and Main. Operator: What happened? Caller: Someone grabbed my bag from my shoulder and ran — about five minutes ago. Operator: Describe the person. Caller: Male, around twenty-five, dark green hoodie and jeans. Ran north. Operator: Officers are on their way. Stay where you are. What was in the bag? Caller: Passport, wallet, and phone.", "qs": [{"q": "Where is the caller?", "opts": ["A building", "Fifth and Main", "A hotel", "The subway"], "ans": 1}, {"q": "What was stolen?", "opts": ["Wallet only", "Wallet and keys", "Passport, wallet, phone", "Phone and laptop"], "ans": 2}, {"q": "Which way did the thief run?", "opts": ["South", "East", "West", "North"], "ans": 3}]}, {"title": "Police statement", "text": "Officer: Give me a full statement from the beginning. Witness: I was walking from the subway to my hotel at nine fifteen PM. Officer: Describe the suspect clearly. Witness: Male, mid-twenties, 180 centimetres, dark hoodie. Tattoo on his right wrist. Officer: What was taken? Witness: My passport and wallet. Credit cards were in my jacket pocket. Officer: You'll need to contact your embassy about the passport. Do you have travel insurance? Witness: Yes, through my bank.", "qs": [{"q": "What time did it happen?", "opts": ["8 PM", "9:15 PM", "10 PM", "9:45 PM"], "ans": 1}, {"q": "Where were the credit cards?", "opts": ["In the bag", "In the wallet", "In the jacket pocket", "Also stolen"], "ans": 2}, {"q": "What does the officer say about the passport?", "opts": ["They can replace it", "Contact the embassy", "It will be found", "Check the lost and found"], "ans": 1}]}, {"title": "Allergic reaction", "text": "Bystander: Someone needs help — allergic reaction, she ate nuts! Passerby: Calling 911 now! Operator: What's the situation? Bystander: Woman having a reaction, throat swelling, allergic to nuts. Operator: Does she have an EpiPen? Bystander: Yes — found it! Operator: Help her use it — right thigh, outer side, hold ten seconds. Emergency services are three minutes away. Bystander: She's used it. Operator: Keep her calm. Paramedics are coming.", "qs": [{"q": "What caused the reaction?", "opts": ["Dairy", "Shellfish", "Nuts", "Medication"], "ans": 2}, {"q": "What does the operator instruct?", "opts": ["Call the hotel", "Use the EpiPen", "Do CPR", "Move her"], "ans": 1}, {"q": "How long until help arrives?", "opts": ["One min", "Two min", "Three min", "Five min"], "ans": 2}]}], "13": [{"title": "Opening a bank account", "text": "Advisor: How can I help? Customer: I'd like to open a current account. I just moved here and need it for my salary. Advisor: We need your passport, proof of address, and employment letter. Do you have those? Customer: Yes, all three. Advisor: Are there monthly fees? Standard account has no monthly fee, but if your balance drops below 500, there's a small charge. Or for eight pounds a month, our premium account includes worldwide travel insurance and a higher overdraft limit.", "qs": [{"q": "What is the account for?", "opts": ["Investment", "Savings", "Salary", "Business"], "ans": 2}, {"q": "What happens below £500?", "opts": ["Account closes", "Small charge", "Limit reduced", "Nothing"], "ans": 1}, {"q": "What's in the premium account?", "opts": ["Credit card", "Free ATM", "Travel insurance", "Cashback"], "ans": 2}]}, {"title": "International transfer", "text": "Customer: I want to send $500 monthly to Russia. Advisor: Set up a standing order in USD via SWIFT wire transfer. Rate today is 88.4 rubles to the dollar. Commission is $15 per transfer. Customer: Can I reduce that? Advisor: Set it as a direct debit — fee drops to $8. You'll get an email confirmation each time. What do I need from the recipient? Advisor: Their full name, IBAN, and the bank's SWIFT code.", "qs": [{"q": "Today's exchange rate?", "opts": ["85 rubles", "88.4 rubles", "90 rubles", "92 rubles"], "ans": 1}, {"q": "How to reduce commission?", "opts": ["Send more money", "Use direct debit", "Currency account", "Can't reduce it"], "ans": 1}, {"q": "What info is needed?", "opts": ["Account number only", "Name, IBAN, SWIFT", "Name and phone", "Just the IBAN"], "ans": 1}]}, {"title": "Fraud on the account", "text": "Customer: I've been a victim of fraud — transactions I didn't make. Advisor: I'm sorry. Let me look at your account. I see a $340 online purchase and two ATM withdrawals yesterday evening. Customer: I was home all evening — none of those are mine. Advisor: I'll freeze the account and dispute all three charges immediately. New card in three working days. Customer: Should I file a police report? Advisor: Yes — we recommend it. I'll email you the dispute reference number.", "qs": [{"q": "How many unauthorised transactions?", "opts": ["One", "Two", "Three", "Four"], "ans": 2}, {"q": "How long for the new card?", "opts": ["One day", "Two days", "Three working days", "One week"], "ans": 2}, {"q": "What does the advisor recommend?", "opts": ["Change PIN", "File police report", "Close account", "Contact credit bureau"], "ans": 1}]}], "14": [{"title": "Sending a parcel abroad", "text": "Postal Worker: What are you sending today? Customer: A parcel to Russia — birthday gift for my parents. Worker: Fragile items? Customer: A glass photo frame — I've wrapped it in bubble wrap. Worker: You'll need a customs form. Contents and value? Customer: Clothes and the frame — about 80 dollars total. Worker: Tracking and insurance? Customer: Yes please — especially with the glass. Worker: With registered mail and insurance, that's fourteen fifty. Estimated ten to fifteen business days. Faster option? Express is twenty-two dollars, four to six days. Customer: I'll go express.", "qs": [{"q": "What fragile item is inside?", "opts": ["Ceramic mug", "Glass photo frame", "Vase", "Mirror"], "ans": 1}, {"q": "Total declared value?", "opts": ["$50", "$70", "$80", "$100"], "ans": 2}, {"q": "How long is express?", "opts": ["2–3 days", "4–6 days", "7–10 days", "10–15 days"], "ans": 1}]}, {"title": "Lost parcel", "text": "Customer: I sent a parcel three weeks ago and it hasn't arrived. Tracking number is GBQ 7724891. Worker: It cleared customs but there's no delivery confirmation. Seems held at destination customs. I'll raise a trace — five to seven working days for a response. Did you insure it? Customer: Yes, I have the certificate of posting. Worker: You can file a claim with that. Maximum compensation is up to 250 on insured parcels. I'll start the trace now.", "qs": [{"q": "Where is the parcel?", "opts": ["Local post office", "Destination customs", "UK depot", "Returned to sender"], "ans": 1}, {"q": "How long for the trace?", "opts": ["2–3 days", "5–7 working days", "2 weeks", "1 month"], "ans": 1}, {"q": "Maximum compensation?", "opts": ["£100", "£150", "£200", "£250"], "ans": 3}]}, {"title": "Overnight delivery service", "text": "Customer: I need overnight delivery — can I do that? Worker: Yes, guaranteed next-day if dropped off before three PM today. Customer: It's a legal document — needs a signature required. Worker: Included in the premium service. Customer: Any prohibited items I should know about? Worker: No liquids, nothing flammable, no loose lithium batteries. Legal documents are fine. Customer: And if the recipient isn't home? Worker: We attempt twice. If nobody's in, we leave a card and they can collect or redirect.", "qs": [{"q": "Drop-off deadline for overnight?", "opts": ["2 PM", "3 PM", "4 PM", "5 PM"], "ans": 1}, {"q": "What is included in premium service?", "opts": ["Tracking only", "Signature on delivery", "Free packaging", "Insurance"], "ans": 1}, {"q": "What if recipient is not home twice?", "opts": ["Parcel returned", "Card left, collect or redirect", "Destroyed", "Held one month"], "ans": 1}]}], "15": [{"title": "Business phone call", "text": "Receptionist: Good morning, Apex Solutions. How can I direct your call? Caller: Could I speak to James Crawford in sales? Receptionist: Can I ask who's calling? Caller: Anna Petrova from Global Marketing Partners. Receptionist: One moment — I'll put you on hold. I'm sorry, James is in a meeting until eleven thirty. Leave a message or call back? Caller: Please ask him to call me back. My number is 07700 900 441. Receptionist: Of course — Anna Petrova, Global Marketing Partners. He'll have your message by eleven thirty.", "qs": [{"q": "Who is the caller trying to reach?", "opts": ["Michael Crawford", "James Crawford", "John Crawford", "James Carter"], "ans": 1}, {"q": "Why can't they speak now?", "opts": ["Another call", "Away from office", "In a meeting", "At lunch"], "ans": 2}, {"q": "What does the caller ask for?", "opts": ["Transfer to voicemail", "Send an email", "A callback", "Schedule a call"], "ans": 2}]}, {"title": "Technical issues on a video call", "text": "Person A: Can everyone hear me? Person B: Yes, you're clear. Someone is muted still. Person C: Sorry — I was on mute. Can you hear me now? Person A: Yes! I'll share my screen. Person B: It's not showing yet. Person A: How about now? Person B: Yes, we can see the slides. Person C: Can everyone mute when not speaking — there's background noise. Person A: Good idea. Agenda today: budget review, then action items from last week. Are we recording? Yes, I'll send it after.", "qs": [{"q": "What was wrong with Person C?", "opts": ["Poor connection", "Wrong extension", "On mute", "Screen share issue"], "ans": 2}, {"q": "Why mute when not speaking?", "opts": ["Speed up call", "Background noise", "Save bandwidth", "Connection dropping"], "ans": 1}, {"q": "What is today's agenda?", "opts": ["Project update and Q&A", "Budget review and action items", "New hire and onboarding", "Sales pitch"], "ans": 1}]}, {"title": "Rescheduling a meeting", "text": "Caller: Hi Sarah — heads-up, I need to reschedule Thursday's call. A stakeholder meeting came in last-minute. Colleague: Friday same time? Caller: Friday's tight — could we do two PM? Colleague: Two PM works. Caller: I'll update the invite. Can you loop in Priya? She has last week's action items. Colleague: Done. Caller: I'll send a follow-up email with the revised agenda before the call.", "qs": [{"q": "Why reschedule?", "opts": ["Michael is ill", "Last-minute stakeholder meeting", "Forgot about it", "Travelling"], "ans": 1}, {"q": "New meeting time?", "opts": ["10 AM Friday", "11 AM Friday", "2 PM Friday", "3 PM Friday"], "ans": 2}, {"q": "Who will be looped in?", "opts": ["Whole team", "Just Sarah", "Priya", "The manager"], "ans": 2}]}], "16": [{"title": "Planning a holiday", "text": "Agent: What does your ideal holiday look like? Client: Warm, culturally rich, not too touristy — two of us, ten days, 3000 per person. Agent: I'd suggest Portugal in May or Croatia in June — shoulder season, cheaper, beautiful weather. What's included in a package? Agent: Flight, hotel, transfers, some activities, usually breakfast. Client: Is it refundable if we cancel? Agent: Some hotels are, some aren't — I always recommend travel insurance. About 45 per person for ten days. Client: Worth it.", "qs": [{"q": "Holiday length?", "opts": ["7 days", "10 days", "2 weeks", "3 weeks"], "ans": 1}, {"q": "Budget per person?", "opts": ["£2,000", "£2,500", "£3,000", "£3,500"], "ans": 2}, {"q": "Travel insurance cost per person?", "opts": ["£25", "£35", "£45", "£55"], "ans": 2}]}, {"title": "Visa questions", "text": "Traveller: I want to visit the US for three weeks. What visa? Agent: For tourism, apply for an ESTA — electronic travel authorisation, 21 dollars, lasts two years. Traveller: Is it guaranteed? Agent: Usually yes. Have you visited Iran, Iraq, or North Korea? Traveller: Never. Agent: Then you should be fine. Apply online, at least 72 hours before travel. Multiple entries allowed — each stay must be under 90 days.", "qs": [{"q": "How long does ESTA last?", "opts": ["6 months", "1 year", "2 years", "5 years"], "ans": 2}, {"q": "ESTA cost?", "opts": ["$14", "$21", "$35", "$72"], "ans": 1}, {"q": "Max stay per visit?", "opts": ["30 days", "60 days", "90 days", "180 days"], "ans": 2}]}, {"title": "Complaining about a tour", "text": "Client: The itinerary I received is completely different from what was advertised. Agent: I'm sorry. Booking reference? Client: BP 4492. Agent: You're right — the Lisbon extension wasn't included and the hotel is lower category. Our error. Two options: full refund, or we rebook with the correct hotel and add the Lisbon days at no cost. Client: I'd like the corrected booking — we've been looking forward to this trip. Agent: I'll have a revised itinerary to you within 24 hours.", "qs": [{"q": "What is wrong with the tour?", "opts": ["Wrong dates", "Different itinerary and lower hotel", "Cancelled flights", "Group too large"], "ans": 1}, {"q": "What does the client choose?", "opts": ["Full refund", "Different destination", "Corrected booking", "Travel credit"], "ans": 2}, {"q": "When will the revised itinerary be sent?", "opts": ["Immediately", "Within 24 hours", "Within 48 hours", "Next week"], "ans": 1}]}], "17": [{"title": "First session with trainer", "text": "Trainer: Any injuries I should know about? Client: Lower back pain — flares up with heavy lifting. Trainer: We'll avoid heavy deadlifts and focus on core strength first. Goals? Client: Lose eight kilos and build functional strength — feel more energetic. Trainer: How many days a week? Client: Four, realistically. Trainer: Four days — two strength, one HIIT, one cardio. Nutrition? Client: I skip breakfast often. Trainer: That's the first thing to fix.", "qs": [{"q": "What injury does the client have?", "opts": ["Knee pain", "Shoulder injury", "Lower back pain", "Ankle problem"], "ans": 2}, {"q": "How many training days per week?", "opts": ["Three", "Four", "Five", "Six"], "ans": 1}, {"q": "First nutrition priority?", "opts": ["More protein", "Calorie deficit", "Fix breakfast skipping", "Reduce carbs"], "ans": 2}]}, {"title": "Progress review", "text": "Trainer: Six weeks in — down four kilos, strength numbers are up! Client: I feel so much better. But I've hit a plateau the last ten days. Trainer: Normal — body adapts. I'll increase weight on compound movements and add a second HIIT session. Client: Muscles have been very sore this week. Trainer: Normal with new exercises. Sleep, protein, rest days. Are you tracking macros? Client: Roughly — I aim high protein. Trainer: Let me send you a proper plan. Two weeks and you'll be through the plateau.", "qs": [{"q": "Weight lost so far?", "opts": ["2 kg", "3 kg", "4 kg", "5 kg"], "ans": 2}, {"q": "How to break the plateau?", "opts": ["Less training", "More weight, second HIIT", "Complete rest week", "Diet change only"], "ans": 1}, {"q": "How often is client getting sports massage?", "opts": ["Weekly", "Every two weeks", "Monthly", "Only when injured"], "ans": 1}]}, {"title": "Nutrition discussion", "text": "Trainer: What do you typically eat on a training day? Client: Oats with protein for breakfast, chicken and salad for lunch, pasta or more protein for dinner. Trainer: Solid. Protein intake? Client: About 100 to 120 grams. Trainer: For your weight and goals, 140 is better. In calorie deficit? Client: I think so, I don't count carefully. Trainer: Maintenance is around 2400. For fat loss, target 1900 to 2000. Training days you can eat up to 2200. One habit to cut: late-night snacking. Client: That's my weakness.", "qs": [{"q": "Recommended protein?", "opts": ["100g", "120g", "140g", "160g"], "ans": 2}, {"q": "Fat loss calorie target?", "opts": ["1500–1700", "1700–1900", "1900–2000", "2000–2200"], "ans": 2}, {"q": "What habit to change?", "opts": ["Skip breakfast", "Eat pasta", "Late-night snacking", "Drinking coffee"], "ans": 2}]}], "18": [{"title": "Tech support call", "text": "Support: How can I help? User: My laptop keeps crashing — freezes about twenty minutes after startup. Support: Model and OS? User: MacBook Pro 2021, macOS Ventura — updated about a week ago. Support: Did anything else change? User: I installed a video editing app around the same time. Support: Possible memory conflict. Open Activity Monitor — what's the memory pressure? User: Yellow — moderate. Support: Clean reboot first. If the problem continues, try uninstalling the editing app and test for an hour.", "qs": [{"q": "How long until freezing?", "opts": ["10 min", "20 min", "30 min", "1 hour"], "ans": 1}, {"q": "Likely cause?", "opts": ["Virus", "Video editing app", "OS update", "Overheating"], "ans": 1}, {"q": "Next step if problem continues?", "opts": ["Buy new laptop", "Reinstall macOS", "Uninstall editing app", "Take to a store"], "ans": 2}]}, {"title": "Privacy and security", "text": "Support: Let's secure your account. Do you have two-factor authentication? User: No — I meant to set it up. Support: That's the number one step. Even with your password, someone can't get in without your phone. User: What else? Support: Use a strong unique password — don't reuse across sites. User: I use the same one everywhere. Support: A password manager would help. And check your social media privacy settings — your location may be visible to everyone. User: I didn't realise. Support: Ten minutes and a huge difference.", "qs": [{"q": "What happened to the user's account?", "opts": ["Phone stolen", "Email hacked", "Credit card used", "Account deleted"], "ans": 1}, {"q": "What is two-factor auth?", "opts": ["A type of password", "Login without password", "Extra step requiring your phone", "Firewall setting"], "ans": 2}, {"q": "What does agent recommend for passwords?", "opts": ["Write them down", "Same everywhere", "Use a password manager", "Change monthly"], "ans": 2}]}, {"title": "Instagram algorithm", "text": "Creator: My reach has really dropped. Support: The algorithm now prioritises video — especially Reels — over static images. Creator: I don't post many Reels. Support: That explains the drop. Post Reels three to five times per week. Use trending audio — it pushes your content further. Creator: What about hashtags? Support: Less important now. Focus on caption quality and engagement in the first hour — that signals the algorithm to share your content. Reply to every comment in the first hour. Creator: I didn't know that.", "qs": [{"q": "What content does the algorithm prioritise?", "opts": ["Long captions", "Carousel photos", "Reels", "Stories"], "ans": 2}, {"q": "Reels per week?", "opts": ["1–2", "3–5", "5–7", "Daily"], "ans": 1}, {"q": "What signals quality to the algorithm?", "opts": ["Many hashtags", "High follower count", "Engagement in first hour", "Posting time"], "ans": 2}]}], "19": [{"title": "Meeting with professor", "text": "Professor: You wanted to discuss your essay draft? Student: I'm not sure my argument is strong enough. Professor: Your thesis is good but you're not engaging with the counter-arguments. You need to address them and explain why your position still holds. Student: I wasn't sure how without undermining my own point. Professor: That's what makes a strong essay — show you understand the other side. Can I have a short extension? Student: Two extra days would help. Professor: Submit by Sunday midnight — one-time only.", "qs": [{"q": "Main weakness of the essay?", "opts": ["Unclear thesis", "Counter-arguments not addressed", "Incomplete bibliography", "Too short"], "ans": 1}, {"q": "Original deadline?", "opts": ["Thursday", "Friday", "Saturday", "Sunday"], "ans": 1}, {"q": "Extra time given?", "opts": ["One day", "Two days", "Three days", "One week"], "ans": 1}]}, {"title": "Course enrolment", "text": "Advisor: Enrolment closes Friday — just in time. Which module? Student: Advanced research methods seminar. Advisor: Four places left. It's a prerequisite for the dissertation. Student: Can I audit it first? Advisor: No — it's assessed. Essay and presentation. Student: GPA requirement? Advisor: 3.5 for honours. Your current GPA is 3.7 — you're fine. Can I enrol now? Advisor: Yes, right here. Confirmation and syllabus by email.", "qs": [{"q": "Enrolment closes?", "opts": ["Today", "Wednesday", "Friday", "Next week"], "ans": 2}, {"q": "How is the module assessed?", "opts": ["Exam only", "Essay only", "Essay and presentation", "Attendance only"], "ans": 2}, {"q": "Student's current GPA?", "opts": ["3.4", "3.5", "3.7", "4.0"], "ans": 2}]}, {"title": "Academic integrity", "text": "Professor: I need to speak about your assignment — concerns about academic integrity. Student: What kind of concerns? Professor: Several passages are very similar to a published article. Did you cite it? Student: I read it but didn't quote it directly. Professor: Even paraphrasing without citation is plagiarism under our policy. Student: I genuinely didn't know. Professor: I believe it was unintentional — resubmit with proper citations within a week. Use APA style. And attend the library citation workshop this Thursday. Student: I will. I'm sorry.", "qs": [{"q": "What is the concern?", "opts": ["Late submission", "Uncited sources", "Wrong topic", "Wrong word count"], "ans": 1}, {"q": "What does the professor decide?", "opts": ["Report the student", "Fail the assignment", "Allow resubmission with citations", "Cancel the assignment"], "ans": 2}, {"q": "What workshop is recommended?", "opts": ["Writing skills", "Citation at the library", "Research methods", "Plagiarism checker tutorial"], "ans": 1}]}], "20": [{"title": "Discussing a film", "text": "Friend A: What did you think? Honestly. Friend B: First two acts were brilliant, but the third act fell apart. The plot twist felt cheap. Friend A: I thought the twist was the best part — didn't see it coming. Friend B: That's the thing — looking back, it didn't feel earned. The screenplay pointed elsewhere. Friend A: The cast was incredible though. Friend B: Absolutely — she was the best thing in it. Rating? Friend B: Seven out of ten. Great start, disappointing finish. Soundtrack was exceptional though.", "qs": [{"q": "What did Friend B like?", "opts": ["First two acts", "Third act", "The ending", "Soundtrack only"], "ans": 0}, {"q": "What did Friend B think of the twist?", "opts": ["Brilliant", "Predictable", "Didn't feel earned", "Best part"], "ans": 2}, {"q": "Friend B's rating?", "opts": ["6/10", "7/10", "8/10", "9/10"], "ans": 1}]}, {"title": "Choosing what to watch", "text": "Person A: What shall we watch? Person B: No heavy dramas — stressful week. Person A: There's a new indie film — road trip comedy, great reviews. Person B: Is it streaming? Person A: Yes. Critically acclaimed, nominated for two awards. Person B: Not a blockbuster then. Cast of unknowns? Person A: Yes — hour and forty-five. Person B: Perfect. No spoilers please! Person A: I'll start it.", "qs": [{"q": "What genre?", "opts": ["Horror", "Heavy drama", "Road trip comedy", "Thriller"], "ans": 2}, {"q": "Where is it available?", "opts": ["Cinema only", "Streaming", "DVD", "Not yet"], "ans": 1}, {"q": "Runtime?", "opts": ["1 hour", "1h 20m", "1h 45m", "2h 10m"], "ans": 2}]}, {"title": "Buying concert tickets", "text": "Box Office: Nearly sold out — limited upper tier seats and standing at the front. Customer: Price difference? Box Office: Standing 45, upper tier 65. Customer: Are standing tickets at the front? Box Office: Within five metres of the stage. Customer: Two standing please. Box Office: Doors open seven, support at eight, main act nine thirty. Merchandise stand at the venue.", "qs": [{"q": "Tickets available?", "opts": ["Front row only", "Upper tier and standing", "Standing only", "Backstage and standing"], "ans": 1}, {"q": "Price of standing tickets?", "opts": ["£35", "£40", "£45", "£65"], "ans": 2}, {"q": "When does main act start?", "opts": ["7 PM", "8 PM", "9 PM", "9:30 PM"], "ans": 3}]}], "21": [{"title": "After the match", "text": "Fan A: What a match! We made the playoffs! Fan B: That penalty in overtime was incredible. Fan A: And that offside call in the second half — completely wrong. Fan B: Very controversial on social media this morning. Fan A: Our MVP was outstanding — best match of the season. Fan B: And the substitutions in the second half changed everything. Fan A: Championship final next weekend — I've already bought tickets. Fan B: Who do we face? Fan A: Either City or United — their qualifier is Thursday.", "qs": [{"q": "What controversial moment happened?", "opts": ["Red card", "Wrong offside call", "Penalty miss", "Disallowed goal"], "ans": 1}, {"q": "What changed the match?", "opts": ["An injury", "Offside call", "Substitutions in second half", "Weather"], "ans": 2}, {"q": "When is the final?", "opts": ["Tonight", "This weekend", "Next weekend", "Two weeks"], "ans": 2}]}, {"title": "Planning a hike", "text": "Hiker A: Summit trail next weekend — twelve kilometres, moderate terrain. Are you in? Hiker B: What altitude? Hiker A: About 1400 metres at the top. Hiker B: Gear? Hiker A: Hiking boots, waterproof layer, trekking poles if you have them. No water source on the upper trail — bring plenty. Wildlife? Deer and sometimes eagles at the summit. Leave no trace. Hiker B: Start time? Hiker A: Seven AM — beat the heat and crowds. Summit by noon, back by three.", "qs": [{"q": "Trail length?", "opts": ["8 km", "10 km", "12 km", "15 km"], "ans": 2}, {"q": "Summit altitude?", "opts": ["800m", "1200m", "1400m", "1800m"], "ans": 2}, {"q": "Start time?", "opts": ["6 AM", "7 AM", "8 AM", "9 AM"], "ans": 1}]}, {"title": "Marathon preparation", "text": "Runner A: First marathon in eight weeks. I'm terrified. Runner B: Eight weeks is enough with a solid base. Long runs? Runner A: Up to 28 kilometres. Runner B: Get one 32k run in before the taper. Runner A: What's the taper? Runner B: Last two to three weeks — reduce mileage, let the body recover. Realistic finish time? About four to four and a half hours based on your 28k runs. Nutrition on race day? Carbs the night before. Gel every 45 minutes during the race. Start slow — number one mistake is going out too fast.", "qs": [{"q": "Weeks until marathon?", "opts": ["6", "8", "10", "12"], "ans": 1}, {"q": "What is the taper?", "opts": ["First week", "Pre-race mileage reduction", "Increase in distance", "The race itself"], "ans": 1}, {"q": "Number one race day mistake?", "opts": ["Eating too much", "Going out too fast", "New shoes", "Not hydrating"], "ans": 1}]}], "22": [{"title": "At the farmers market", "text": "Vendor: Everything local and in season. What are you looking for? Customer: Dinner for eight Saturday — Mediterranean theme. Need good tomatoes and fresh herbs. Vendor: These San Marzano tomatoes were picked yesterday — perfect for a sauce. Basil, thyme, rosemary — all locally grown. Customer: Are they organic? Vendor: Certified organic, no pesticides. How do I prepare them? Vendor: Slow roast at 180 with olive oil and garlic — three hours. Incredibly sweet. Customer: A dozen eggs too. How much? Vendor: Fourteen fifty for everything.", "qs": [{"q": "Cooking for how many?", "opts": ["Four", "Six", "Eight", "Ten"], "ans": 2}, {"q": "Tomato preparation?", "opts": ["Boil in water", "Slow roast 180 degrees", "High heat grill", "Serve raw"], "ans": 1}, {"q": "Total price?", "opts": ["£10.50", "£12.00", "£14.50", "£16.00"], "ans": 2}]}, {"title": "Cooking class", "text": "Chef: Today — classic pasta sauce from scratch. Dice the onions small and even. Saute in olive oil — medium heat, frequently. We want soft and translucent, not brown. About eight minutes. Add minced garlic. Then tomatoes — simmer twenty-five minutes. Season generously with salt and pepper. When to add fresh basil? Student: Now? Chef: No — at the very end, off the heat. Heat destroys the flavour. Texture should be thick but not dry. Taste as you go.", "qs": [{"q": "Heat level for onions?", "opts": ["Low", "Medium", "High", "Didn't say"], "ans": 1}, {"q": "How long does sauce simmer?", "opts": ["10 min", "15 min", "20 min", "25 min"], "ans": 3}, {"q": "When to add basil?", "opts": ["Start", "After onions", "During simmering", "End, off heat"], "ans": 3}]}, {"title": "Dietary requirements in restaurant", "text": "Waiter: Any allergies or dietary requirements? Guest A: Dairy intolerance — no cream, butter, or cheese. Guest B: I'm vegan — completely plant-based. Waiter: For you — grilled salmon with seasonal vegetables, no dairy. Guest A: Perfect. Guest B: For me? Waiter: Chef's vegan dish tonight — roasted cauliflower with tahini sauce and organic greens, locally sourced. Is the tahini house-made? Waiter: Yes, artisanal — fresh daily. Greens from the farmers market this morning. Guest B: I'll have that.", "qs": [{"q": "Guest A's dietary issue?", "opts": ["Nut allergy", "Gluten intolerance", "Dairy intolerance", "Vegan"], "ans": 2}, {"q": "Vegan dish tonight?", "opts": ["Pasta", "Roasted cauliflower with tahini", "Vegetable soup", "Mushroom risotto"], "ans": 1}, {"q": "Where are the greens from?", "opts": ["Restaurant garden", "Supermarket", "Farmers market", "Local delivery"], "ans": 2}]}], "23": [{"title": "Property viewing", "text": "Agent: Two bedrooms, open plan, en-suite in the master. Client: Natural light is excellent — that was my biggest concern. Agent: South-facing — sun all afternoon. Floor plan matches what you see. Client: Freehold or leasehold? Agent: Leasehold — 125 years remaining, ground rent 200 a year. Client: Survey available? Agent: Not yet — you'd commission one after making an offer. I'd strongly recommend it. Asking price is 420,000. Strong interest, so move quickly.", "qs": [{"q": "Which direction does the flat face?", "opts": ["North", "East", "South", "West"], "ans": 2}, {"q": "What type of ownership?", "opts": ["Freehold", "Shared ownership", "Leasehold", "Rented"], "ans": 1}, {"q": "What to do after making an offer?", "opts": ["Meet neighbours", "Commission a survey", "Check lease history", "Visit again"], "ans": 1}]}, {"title": "Mortgage discussion", "text": "Advisor: Have you spoken to a mortgage advisor? Buyer: Yes — mortgage in principle for 280,000. Down payment 70,000. Advisor: Total 350,000. Fixed or variable rate? Buyer: Fixed — I want the certainty. Advisor: A 5-year fixed at 4.2% would give monthly repayments of around 1350. Conveyancing costs? Budget 2000 to 2500 for the solicitor. Stamp duty on 350K is 7500. Buyer: So about 10,000 in fees on top of the deposit? Advisor: Roughly, yes.", "qs": [{"q": "Total budget?", "opts": ["£280k", "£300k", "£350k", "£420k"], "ans": 2}, {"q": "Preferred rate type?", "opts": ["Variable", "Fixed", "Tracker", "Interest-only"], "ans": 1}, {"q": "Stamp duty on £350k?", "opts": ["£5,000", "£7,500", "£10,000", "£12,500"], "ans": 1}]}, {"title": "Making an offer", "text": "Client: We'd like to make an offer — 395, which is 25 under asking. Agent: Sellers are motivated — on market four months. I'll put it to them. Client: Is there a chain? Agent: Yes — they're purchasing elsewhere. Risk of gazumping? Agent: Always possible. I'd suggest 405 as a stronger position. Client: Let's go to 400 — fair given survey costs. Agent: I'll call them now. If they accept — can you move quickly to completion? Client: Yes — our solicitor is already instructed.", "qs": [{"q": "Initial offer?", "opts": ["£390k", "£395k", "£400k", "£405k"], "ans": 1}, {"q": "How long on the market?", "opts": ["2 months", "3 months", "4 months", "6 months"], "ans": 2}, {"q": "Final agreed offer?", "opts": ["£395k", "£398k", "£400k", "£405k"], "ans": 2}]}], "24": [{"title": "Business meeting", "text": "Client: Your pricing is higher than competitors. Executive: What's driving the comparison — just price, or outcomes too? Client: Both. Executive: Our system has 94% client retention over five years. We save your team 15 hours per week. At your hourly cost, the premium pays for itself in under two months. Client: What's flexible? Executive: Payment terms and onboarding timeline. IP ownership is a firm line. Client: We'll need an NDA first. Executive: I have one ready — shall we sign today?", "qs": [{"q": "Client's main concern?", "opts": ["Timeline", "Quality", "Pricing", "Team size"], "ans": 2}, {"q": "Client retention rate?", "opts": ["85%", "89%", "94%", "97%"], "ans": 2}, {"q": "What is a firm line?", "opts": ["Payment terms", "IP ownership", "Delivery timeline", "Support level"], "ans": 1}]}, {"title": "Investor pitch", "text": "Investor: What problem do you solve? Founder: Small businesses waste 12 hours a week on invoicing. We automate it. Investor: Value versus competition? Founder: Three times faster to set up, forty percent cheaper at scale. AI learns each client's patterns within two weeks. Market share? Founder: 0.3% of target market — twelve months of operation. ROI for customers? Average client saves 8000 per year, software costs 1200. Investor: Strong ROI. Scalable? Founder: Completely — ten or ten thousand clients, same infrastructure.", "qs": [{"q": "Hours wasted by small businesses?", "opts": ["8 hours", "10 hours", "12 hours", "15 hours"], "ans": 2}, {"q": "How much cheaper at scale?", "opts": ["20%", "30%", "40%", "50%"], "ans": 2}, {"q": "Average annual saving per client?", "opts": ["$5,000", "$6,000", "$8,000", "$10,000"], "ans": 2}]}, {"title": "Negotiation deadlock", "text": "Party A: We've reached a deadlock on the exclusivity clause. Party B: We can't accept eighteen months — too long. Party A: What would you accept? Party B: Six months, then both parties review. Party A: That's not enough for ROI. We'd consider twelve. Party B: Nine months — performance review at six. If targets met, extend to twelve automatically. Party A: Interesting counteroffer. I'll consult our board — answer in twenty minutes. I think nine with a review clause is workable.", "qs": [{"q": "What's the deadlock about?", "opts": ["Pricing", "Timeline", "Exclusivity clause", "Payment terms"], "ans": 2}, {"q": "Party B's compromise?", "opts": ["6 months fixed", "12 months with review", "9 months with 6-month review", "No exclusivity"], "ans": 2}, {"q": "Party A's response?", "opts": ["Deal closed", "Need a week", "Answer in 20 minutes", "Reject the offer"], "ans": 2}]}], "25": [{"title": "Store complaint", "text": "Customer: I'd like to speak to the manager on duty. Manager: How can I help? Customer: I bought this jacket three weeks ago — the zip broke after wearing it twice. Manager: That's a manufacturing defect. Refund or exchange? Customer: Full refund. I've also lost confidence in quality and want to log a formal complaint. Manager: I'll process the refund and flag this to head office. Three to five business days — here's your reference number.", "qs": [{"q": "What is defective?", "opts": ["Button missing", "Zip broken", "Seam torn", "Colour faded"], "ans": 1}, {"q": "What does customer request?", "opts": ["Exchange", "Store credit", "Full refund", "Partial refund"], "ans": 2}, {"q": "Refund timing?", "opts": ["Immediately", "1–2 days", "3–5 business days", "Two weeks"], "ans": 2}]}, {"title": "Hotel complaint", "text": "Guest: I need to raise a formal complaint — the heating in my room wasn't working. I reported it at ten PM, nobody came. Manager: I'm so sorry — maintenance was logged but not followed up. I'd like to offer a complimentary breakfast, full refund for last night, and a discount on a future stay. Guest: I'd like that in writing. Manager: I'll email it within the hour. And a quiet room for tonight? Guest: Please. Manager: Room 301, top floor — guaranteed quiet. Already sorted.", "qs": [{"q": "What was wrong?", "opts": ["No hot water", "Noisy neighbours", "Broken heating", "No WiFi"], "ans": 2}, {"q": "Three things offered?", "opts": ["Breakfast, half refund, free room", "Breakfast, full refund, future discount", "Upgrade, dinner, full refund", "Late checkout, breakfast, minibar"], "ans": 1}, {"q": "New room?", "opts": ["Ground floor", "Second floor", "Room 301, top floor", "Same floor, different room"], "ans": 2}]}, {"title": "Online review response", "text": "Manager: I'm calling about the review you left online. We take all feedback seriously. You mentioned dismissive service and unresolved complaint. Customer: The staff member said there was nothing they could do and walked away. Manager: Unacceptable — I've spoken to the team. What outcome would have satisfied you at the time? Customer: An apology and an exchange or refund — it was defective. Manager: I'd like to offer a full refund and a twenty percent goodwill voucher. Customer: Very generous. I appreciate you calling. Manager: Your experience matters.", "qs": [{"q": "Why did manager call?", "opts": ["Promotion", "Respond to online review", "Confirm order", "Invite back"], "ans": 1}, {"q": "How did staff behave?", "opts": ["Helpful", "Apologetic", "Dismissive and walked away", "Escalated it"], "ans": 2}, {"q": "What is offered?", "opts": ["Replacement only", "Full refund and 20% voucher", "Store credit", "Apology letter"], "ans": 1}]}], "26": [{"title": "Wedding toast", "text": "Speaker: Ladies and gentlemen — a few words. I've known Tom fifteen years. What I love about Tom and Anna is that they make each other better. Tom — you became calmer the moment she walked in. And Anna — Tom introduced you to camping, which you describe as the worst idea anyone has ever had. And yet you went back five times. That is love. Please raise your glasses. To a lifetime of adventure, laughter, and terrible camping trips. To Tom and Anna!", "qs": [{"q": "How long has speaker known Tom?", "opts": ["10 years", "12 years", "15 years", "20 years"], "ans": 2}, {"q": "What did Tom introduce Anna to?", "opts": ["Rock climbing", "Camping", "Sailing", "Running"], "ans": 1}, {"q": "The toast is to?", "opts": ["Health and happiness", "Adventure, laughter and camping trips", "Long marriage", "Success and love"], "ans": 1}]}, {"title": "Wedding planning", "text": "Couple: Intimate — about sixty guests. Planner: Venue? Couple: Country house — romantic, nice gardens. Planner: Dress code? Couple: Smart casual — comfortable, not stressed. Planner: Sit-down dinner or cocktail? Couple: Sit-down with seating plan. Planner: Set up the gift registry early — takes the guesswork away for guests. RSVPs by end of next month. First dance song chosen? Couple: Something unusual — we want people surprised.", "qs": [{"q": "Guest count?", "opts": ["40", "50", "60", "80"], "ans": 2}, {"q": "Dress code?", "opts": ["Black tie", "Formal", "Smart casual", "Casual"], "ans": 2}, {"q": "RSVPs by?", "opts": ["This week", "End of this month", "End of next month", "Two months"], "ans": 2}]}, {"title": "Anniversary celebration", "text": "Friend A: Happy anniversary — ten years! Friend B: A real milestone. Tom planned a surprise — booked the restaurant from our first date. Same table, same waiter. The waiter remembered us! Friend A: Incredibly thoughtful. A heartfelt gesture. Friend B: He also gave a little speech — just the two of us. Brought me to tears. Friend A: You're an example to everyone. Here's to many more! Friend B: Raise a glass tonight at dinner — please join us. Friend A: We'd be honoured. Count us in!", "qs": [{"q": "Years celebrating?", "opts": ["5", "8", "10", "15"], "ans": 2}, {"q": "Tom's surprise?", "opts": ["Trip abroad", "Party with friends", "First-date restaurant", "Jewellery"], "ans": 2}, {"q": "Friend A at the end?", "opts": ["Can't come", "Will send gift", "Honoured, will join", "Travelling"], "ans": 2}]}], "27": [{"title": "National park guidelines", "text": "Ranger: Stay on the marked trail at all times. Leave no trace — carry out everything you carry in. Wildlife on the trail? Yes — deer, occasionally bears at higher altitudes. If you see a bear, don't run — back away slowly. Terrain above 800 metres is rocky — appropriate footwear essential. Photography is encouraged but don't approach wildlife. From a distance is always best.", "qs": [{"q": "What to do if you see a bear?", "opts": ["Run", "Shout", "Back away slowly", "Climb a tree"], "ans": 2}, {"q": "Terrain above 800 metres?", "opts": ["Flat and easy", "Sandy", "Rocky", "Muddy"], "ans": 2}, {"q": "Wildlife photography?", "opts": ["Strictly forbidden", "Yes — don't approach", "Certain areas only", "With permit only"], "ans": 1}]}, {"title": "Ecology conversation", "text": "Person A: This park is carbon neutral now — offsets through the nature reserve. The glacier has shrunk by thirty percent in twenty years though. Person B: Climate change is accelerating it. Permafrost beneath is melting — affects the whole ecosystem. Person A: I reduce my carbon footprint — cycle to work, eat less meat, reduce flying. Person B: Every action counts. But systemic change is needed — renewable energy at scale, stopping deforestation. Entrance fees here support the endangered species programme. Person A: That's reassuring.", "qs": [{"q": "Glacier shrank by?", "opts": ["10%", "20%", "30%", "50%"], "ans": 2}, {"q": "What does Person A do for the environment?", "opts": ["Only recycles", "Cycles, eats less meat, reduces flying", "Solar panels only", "Buys offsets"], "ans": 1}, {"q": "What do entrance fees support?", "opts": ["Trail maintenance", "Staff salaries", "Endangered species programme", "Marketing"], "ans": 2}]}, {"title": "Eco-tourism trail", "text": "Guide: This is an eco-tourism trail — minimal impact everything. Stay on the marked path — we never walk off-trail. Why? Biodiversity depends on undisturbed habitat. One person off-trail seems small, but multiply by a thousand visitors and you damage the ecosystem significantly. Don't pick plants or disturb wildlife — even moving a rock affects micro-organisms underneath. This trail funds the nature reserve and the local community. At the summit — evidence of deforestation on the hill opposite. A stark contrast.", "qs": [{"q": "Why stay on the path?", "opts": ["To avoid getting lost", "Protect biodiversity and habitat", "Safety from wildlife", "It's the law"], "ans": 1}, {"q": "What to see from the summit?", "opts": ["The glacier", "A village", "Evidence of deforestation", "A waterfall"], "ans": 2}, {"q": "What does the trail fund?", "opts": ["Nature reserve only", "Guide's salary", "Nature reserve and local community", "Government research"], "ans": 2}]}], "28": [{"title": "Coaching session — feeling stuck", "text": "Coach: You mentioned feeling stuck. What does it actually feel like? Client: Like I'm moving but not going anywhere. Busy all day but don't know what I've built. Coach: When did you last feel genuinely aligned? Client: About two years ago — working on something that actually mattered. Coach: What changed? Client: I took a promotion. More money, less meaning. Coach: You miss impact — seeing results of your work. This isn't a skills problem — it's an alignment problem. Your resilience is intact. But your purpose is unclear. Client: Yes — exactly it.", "qs": [{"q": "How does client describe being stuck?", "opts": ["Tired and unmotivated", "Moving but not going anywhere", "Too much work", "Bored with nothing to do"], "ans": 1}, {"q": "When last felt aligned?", "opts": ["Last year", "About two years ago", "Five years ago", "At university"], "ans": 1}, {"q": "What does the coach say the real problem is?", "opts": ["Lack of skills", "Too much stress", "Alignment — unclear purpose", "Low self-esteem"], "ans": 2}]}, {"title": "Therapy session — burnout", "text": "Therapist: You haven't been sleeping well. How long? Client: About three months — wake at four AM thinking about work. Therapist: That sounds like burnout — the mind can't switch off. Triggers? Client: Deadlines. And my inner critic gets very loud when I feel I haven't done enough. Therapist: Boundaries at work — do you disconnect in evenings? Client: Almost never — I check emails until midnight. That's a core issue. We'll work on setting boundaries. Current coping mechanisms? Client: I distract myself — phone, TV, food. Therapist: Those are avoidance mechanisms, not restorative ones.", "qs": [{"q": "Sleep problem duration?", "opts": ["1 month", "2 months", "3 months", "6 months"], "ans": 2}, {"q": "Main trigger?", "opts": ["Difficult colleagues", "Deadlines and inner critic", "Commuting", "Financial stress"], "ans": 1}, {"q": "What does therapist say about coping mechanisms?", "opts": ["They're healthy", "Good but need improving", "Avoidance — not restorative", "Need medication instead"], "ans": 2}]}, {"title": "Coaching session — imposter syndrome", "text": "Coach: You mentioned feeling like an imposter. Tell me — what specifically have you achieved? Client: I built a team from three to twenty people. Grew revenue by sixty percent in two years. Coach: Did luck do that? Client: No... Coach: That's a growth mindset challenge — replacing fixed thinking with evidence. You didn't get lucky. You executed. Client: When you put it that way, I can see it. Coach: Write down three specific achievements before next session. Evidence defeats imposter syndrome every time.", "qs": [{"q": "What is the client experiencing?", "opts": ["Burnout", "Social anxiety", "Imposter syndrome", "Low self-esteem"], "ans": 2}, {"q": "Client's achievement?", "opts": ["Team from 3 to 20, revenue 60%", "Launched a new product", "Won an award", "Managed a merger"], "ans": 0}, {"q": "What is the homework?", "opts": ["Journal feelings", "Meditate 10 min", "Write 3 specific achievements", "Speak to HR"], "ans": 2}]}]};